#include <bits/stdc++.h>
using namespace std;
long long totalSetBits(long long n){
    long long count = 0;
    for(int i = 0; (1LL<<i) <= n; ++i){
        long long blockSize = 1LL << (i+1);
        long long fullBlocks = n / blockSize;
        count += fullBlocks * (1LL<<i);
        long long remainder = n % blockSize;
        count += max(0LL, remainder - (1LL<<i) + 1);
    }
    return count;
}
int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    long long n;
    if(!(cin>>n)) return 0;
    cout << totalSetBits(n);
    return 0;
}
